import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUTERONOMY = {
"26": {
"1": "<p>Entry into the land activates this firstfruits obligation. The land is framed from the outset as gift rather than conquest: &quot;the land the LORD your God is giving you as your inheritance&quot; (naḥălâ). Possession and settlement are preconditions, not grounds for self-congratulation — the first response to receiving the land is to return its firstfruits to the giver.</p>",
"2": "<p>The firstfruits basket: &quot;the first of all the produce you harvest from the soil.&quot; The first portion functions as the representative part of the whole — giving it acknowledges that the entire harvest belongs to YHWH. The basket is brought to &quot;the place the LORD your God will choose as his dwelling,&quot; Deuteronomy&apos;s recurring formula for the centralized sanctuary, later identified as Jerusalem. The ritual is both agricultural and theological: harvest meets covenant at the altar.</p>",
"3": "<p>The declaration to the priest: &quot;I declare today before the LORD your God that I have come into the land he swore to our ancestors to give us.&quot; This is a covenantal speech act — the worshipper formally testifies that the ancestral promise has been kept. &quot;Today&quot; (hayyôm) is the Deuteronomic marker of present covenant reality; the fulfillment is not merely historical but personally appropriated in this moment of offering.</p>",
"4": "<p>The priest sets the basket before the altar — the offering is formally presented to YHWH. The worshipper&apos;s hand releases the gift; the priest mediates its presentation. The gesture enacts ownership transfer: what was the farmer&apos;s product becomes YHWH&apos;s firstfruits. The altar is the boundary between human labor and divine claim.</p>",
"5": "<p>The &quot;wandering Aramean&quot; creed: &quot;My father was a wandering Aramean.&quot; This is among the oldest credal confessions in the Hebrew Bible. Gerhard von Rad identified it as a pre-Deuteronomic cultic credo (&quot;The Form-Critical Problem of the Hexateuch,&quot; 1938), a compressed liturgical recital of Israel&apos;s founding acts. The &quot;Aramean&quot; father is Jacob, whose connections to Aram (Laban&apos;s household, Gen 28–31) and whose name became Israel make him the paradigmatic ancestor. ʾōḇēḏ means &quot;wandering/perishing&quot; — the ancestor was a marginalized fugitive before becoming a nation. Egypt: &quot;few people&quot; becoming &quot;great, mighty, and numerous&quot; traces the Abrahamic promise of Gen 12:2 toward its fulfillment.</p>",
"6": "<p>Egyptian oppression condensed into three verbs: &quot;treated us harshly&quot; (wayyārēʿû), &quot;oppressed us&quot; (wayʿannûnû), &quot;imposed ruthless forced labor&quot; (wayyittənû ʿālaynû ʿăḇōḏâ qāšâ). The creed does not linger on suffering details; it recites the pattern — affliction followed by divine rescue — as covenant template. This becomes the liturgical skeleton of the Passover retelling.</p>",
"7": "<p>The cry and divine response: &quot;we cried to the LORD... and the LORD heard our voice and saw our misery, our hardship, and our oppression.&quot; Three objects of divine attention — ʿŏnî (misery/affliction), ʿămāl (toil/hardship), laḥaṣ (oppression/pressure) — mark that YHWH witnessed the full depth of Israel&apos;s suffering before acting. This is not a god who rescues from a distance; the divine attention precedes the divine intervention.</p>",
"8": "<p>The Exodus formula: &quot;a mighty hand and an outstretched arm, with great awe-inspiring acts and with signs and wonders.&quot; This is Deuteronomy&apos;s standard Exodus summary (cf. 4:34; 5:15; 7:19). The five-fold description — mighty hand, outstretched arm, great awe-inspiring acts, signs, wonders — covers both the power of the agent and the visibility of the acts. It becomes the backbone of the Passover Haggadah, which quotes Deut 26:5–8 directly as the core confession narrated at the seder table each year.</p>",
"9": "<p>&quot;He brought us to this place and gave us this land — a land flowing with milk and honey.&quot; The promise-fulfillment arc compressed into one sentence: the God who heard the cry in Egypt brought the people to the specific place he had sworn to give. &quot;Land flowing with milk and honey&quot; (ʾereṣ zāḇat ḥālāḇ ûḏĕḇaš) is the standard Promised Land formula (Exod 3:8, 17; Num 13:27; Deut 6:3; 8:7–9; 11:9), evoking agricultural abundance as sign of covenantal blessing.</p>",
"10": "<p>The offering concludes with prostration: &quot;bow in worship before him&quot; — ḥāwâ, the gesture of full submission before the sovereign. The farmer who brought his produce now lies before YHWH. The circuit is complete: land received, firstfruits returned, worship offered. The personal address &quot;LORD, I bring&quot; gives the ritual an intimate, direct character — not impersonal obligation but personal gratitude before a personal God.</p>",
"11": "<p>&quot;Rejoice in all the good things the LORD your God has given to you and your household — you, the Levite, and the foreigner living among you.&quot; The feast of firstfruits is explicitly communal and inclusive. The Levite (landless by covenant design) and the foreign resident (without ancestral inheritance) are named participants in the joy. Deuteronomy&apos;s social vision: wealth received from YHWH is wealth shared within the covenant community, which extends to the economically and legally vulnerable.</p>",
"12": "<p>The triennial tithe: in the third year (šĕnat hammaʿăśēr), the tithe stays local rather than being brought to the central sanctuary. It is distributed to the Levite (no land), the foreigner (gēr, no ancestral plot), the fatherless (yātôm, no paternal protector), and the widow (ʾalmānâ, no husband). This is a systematic agricultural welfare mechanism embedded in Israel&apos;s calendar — every three years the harvest cycle funds a structured redistribution to those outside the normal economic household.</p>",
"13": "<p>The tithe declaration begins: &quot;I have removed from my house the sacred portion and given it to the Levite, the foreigner, the fatherless, and the widow, exactly as you commanded.&quot; The worshipper must give a formal accounting to YHWH — not just performing the act but testifying to its completeness and accuracy. Three specific denials follow (vv.13–14): no commandment violated, no tithe forgotten, no defilement in handling.</p>",
"14": "<p>Three prohibitions accompany the tithe: (1) not eaten while in mourning (ḥāḇal, mourning-taboo; the sacred tithe must not be contaminated by ritual impurity associated with death); (2) not handled while unclean (ritual purity was required for handling consecrated things); (3) not offered to the dead (wĕlōʾ-nātattî mimmennû lĕmēt). This third prohibition is the most theologically pointed — offering food to the dead was an ANE mortuary cult practice (ancestor feeding), widespread in Mesopotamia and Canaan. Israel&apos;s tithe is for the living poor, not for ancestral spirits.</p>",
"15": "<p>The prayer for blessing closes the declaration: &quot;Look down from your holy dwelling in heaven and bless your people Israel and the land you have given us.&quot; YHWH is enthroned in heaven (šāmaʿim — his majestic dwelling), yet his blessing reaches down into the soil and people of the land. The prayer links cosmic theology with agrarian life — heaven and land are not separate realms but the upper and lower poles of a single covenantal economy.</p>",
"16": "<p>&quot;Today the LORD your God commands you to follow these statutes and ordinances.&quot; The covenant call is present-tense and urgent. Deuteronomy&apos;s &quot;today&quot; (hayyôm) is a rhetorical device that makes every covenant renewal contemporaneous — Moses speaks across generations. Keeping the commandments &quot;with all your heart and with all your soul&quot; echoes the Shema&apos;s demand (6:5) and signals that legal compliance is never merely external.</p>",
"17": "<p>Israel&apos;s mutual declaration: &quot;You have declared the LORD to be your God.&quot; The verb heeʾamartā (hiphil of ʾāmar) means &quot;to cause to say, to formally declare.&quot; Israel publicly affirms YHWH as covenant suzerain with full obligation: walk in his ways, keep his statutes/commandments/ordinances, obey him. This is the vassal&apos;s side of the suzerainty-treaty: accepting the great king&apos;s authority and its corresponding demands. Meredith Kline identified Deuteronomy&apos;s treaty-structure parallel to Hittite suzerainty treaties, with this verse as the vassal&apos;s oath.</p>",
"18": "<p>YHWH&apos;s reciprocal declaration: &quot;The LORD has declared today that you are his treasured people, as he promised.&quot; ʿam sĕgullâ — &quot;treasured possession/prized property&quot; — is the technical covenant term for Israel&apos;s special status (Exod 19:5; Deut 7:6; 14:2; Mal 3:17; Ps 135:4). The treaty structure requires both parties to make declarations: the vassal in v.17 and the suzerain here. YHWH formally claims Israel as his own on the same day Israel claims YHWH. The covenant is a mutual oath enacted in liturgical speech.</p>",
"19": "<p>The destiny of the treasured people: &quot;he will set you in praise, fame, and honor high above all nations he has made.&quot; Israel&apos;s election is not for isolation but for covenantal visibility among the nations — the Abrahamic mission (Gen 12:3: &quot;all peoples on earth will be blessed through you&quot;) fulfilled through covenant faithfulness. &quot;A people holy to the LORD your God&quot; — qāḏôš, set apart for YHWH&apos;s purposes. Holiness and exaltation are the telos of the sĕgullâ identity; the covenant journey that began with a wandering Aramean ends with a people distinguished among the nations for their God.</p>"
},
"27": {
"1": "<p>Moses and the elders speak together — the only place in Deuteronomy where Moses delivers a charge jointly with the elders (ziqnê yiśrāʾēl). This signals the emerging transfer of leadership to the community&apos;s elder structure post-Moses. The charge is simple: &quot;Keep every commandment I am giving you today.&quot; The ceremony ahead is the formal covenant-entry liturgy for the land.</p>",
"2": "<p>Large stones coated with plaster (wĕśadtā ʾōtām baśśîḏ) — a writing surface for public inscription. The plastered-stone technique is attested archaeologically: the Deir Alla inscription (8th century, Jordan) used plastered walls for text. The command is for the day of Jordan crossing — the first act in the land is the public display of the covenant law, not military operations or territorial consolidation.</p>",
"3": "<p>&quot;Write on these stones all the words of this law when you cross over.&quot; The Deuteronomic torah is not a priestly secret; it is publicly displayed on monumental stones at the entry point of the land. The repeated formula &quot;land flowing with milk and honey&quot; and the ancestral promise anchor the law in the covenant history — the law is not an abstract legal code but the terms of the relationship with the God who brought them there.</p>",
"4": "<p>Mount Ebal — strikingly, the plastered stones are set up on the mountain of cursing rather than the mountain of blessing (Gerizim). The law stands on the mountain of sanctions, not the mountain of rewards. The law&apos;s primary horizon is the curse-sanction that enforces covenant faithfulness. Joshua 8:30–35 records the actual fulfillment of this ceremony after the initial Canaanite campaigns.</p>",
"5": "<p>The altar of uncut stones: &quot;an altar to the LORD your God out of stones that no iron tool has touched.&quot; ʾăḇānîm šĕlēmôt (complete/whole stones) — the prohibition of iron tools on the altar echoes Exod 20:25. The rationale remains debated: some see a distinction between sacred/natural materials and human technological manufacture; others suggest that iron implements, associated with weapons and warfare, were ritually inappropriate for the altar of the God of life. The uncut stones make an aniconic, unadorned altar — no sculpted imagery, no craft enhancement.</p>",
"6": "<p>Burnt offerings on the uncut altar — ʿōlôt, wholly consumed offerings ascending entirely to YHWH. The first liturgical act at the altar of the new land is total consecration: nothing is retained, everything is surrendered to YHWH. The land is entered under the sign of complete devotion before it is claimed as a place of human settlement.</p>",
"7": "<p>Peace offerings and eating follow the burnt offerings — šĕlāmîm, the communion/fellowship offering where portions are shared among the worshippers. The covenantal feast follows the covenantal oath. &quot;Rejoicing in the presence of the LORD your God&quot; is the experiential content of covenant entry: the relationship with YHWH is not merely obligatory but celebratory. The meal at the altar unites the people with their God and with each other.</p>",
"8": "<p>&quot;Write all the words of this law on the stones very clearly&quot; — bāʾēr hēṭēḇ, &quot;explain/make plain thoroughly.&quot; The inscription must be legible and comprehensible to the entire people. This is the Deuteronomic democratization of the law: the covenant document is not lodged in the temple&apos;s inner sanctuary for priestly access only but displayed publicly for all to read. The word bāʾēr (to explain, make clear) connects to the title &quot;Deuteronomy&quot; (the LXX translates Deut 17:18 as to deuteronomion touto, &quot;this second law,&quot; from this root&apos;s connotation of plain re-statement).</p>",
"9": "<p>&quot;Be silent, Israel, and listen&quot; (hasskēt ûšĕmaʿ yiśrāʾēl) — a solemn call to attention from Moses and the Levitical priests together. Then the declaration: &quot;Today you have become the people of the LORD your God.&quot; The Jordan crossing is not merely geographic; it is covenantal. The moment of entering the land is the moment of formally becoming YHWH&apos;s covenant people at the site of the law&apos;s promulgation. The Ebal ceremony enacts this constitutive identity.</p>",
"10": "<p>&quot;Obey the LORD your God by keeping his commandments and statutes that I am giving you today.&quot; Becoming YHWH&apos;s people (v.9) and obeying YHWH&apos;s law (v.10) are inseparable. The identity precedes the obligation — &quot;you have become his people, therefore obey&quot; — not &quot;obey in order to become his people.&quot; Covenant membership is the foundation of covenant ethics, not its reward.</p>",
"11": "<p>&quot;On that same day Moses gave this command.&quot; The ceremony is immediate and specific — not a vague future obligation but a command tied to the specific day of covenant entry. The urgency of &quot;that same day&quot; underlines that covenant ratification cannot be deferred once the threshold of the land has been crossed.</p>",
"12": "<p>Six tribes on Mount Gerizim for blessing: Simeon, Levi, Judah, Issachar, Joseph, and Benjamin. These are primarily the sons of Leah (Simeon, Levi, Judah, Issachar, Zebulun) and Rachel (Joseph = Ephraim + Manasseh, Benjamin), minus Zebulun. The tribal arrangement for blessing and curse has generated extensive discussion; the division is not entirely genealogical. Gerizim stands south of the valley between the mountains; the natural amphitheater effect would allow voices to carry across.</p>",
"13": "<p>Six tribes on Mount Ebal for the curse: Reuben, Gad, Asher, Zebulun, Dan, and Naphtali. Four of these are sons of the maidservants Bilhah and Zilpah (Gad, Asher, Dan, Naphtali); Reuben is Leah&apos;s eldest but was disgraced (Gen 35:22, sleeping with Bilhah); Zebulun is Leah&apos;s. The curse-side tribes are those with marginalized or complicated status in the ancestral narratives. Joshua 8:33 confirms the ceremony was enacted after Ai.</p>",
"14": "<p>The Levites call out in a loud voice (qôl rām) — the curse-pronouncements are not whispered legal penalties but liturgical proclamations heard by the entire assembly. The Levites serve as the covenant-mediating tribe, the voice of YHWH&apos;s sanctions among the people. The public character of the Amen-response makes the entire community complicit in covenant accountability: everyone hears, everyone responds, everyone is bound.</p>",
"15": "<p>First curse: secret idolatry — &quot;whoever carves or casts an idol... and sets it up in secret&quot; (bassāter). The first commandment&apos;s prohibition on images is here applied specifically to hidden image-worship. Public apostasy was liable to judicial sanction (Deut 17:2–7); this curse fills the gap for secret sins that human courts cannot reach. The congregational Amen transforms the curse-formula into a covenantal oath: the people actively invoke the curse upon anyone — including themselves — who commits this hidden sin.</p>",
"16": "<p>Second curse: contempt for parents (mĕqallēh ʾāḇîw wĕʾimmô, &quot;whoever dishonors/treats with contempt his father or mother&quot;). The Fifth Commandment (Deut 5:16) commanded positive honor; this curse addresses its negative violation. Parents represent the intergenerational covenant line — to shame them is to tear the fabric of ancestral covenant transmission. The honor-shame culture of the ANE made parental contempt a social and religious offense of the first order.</p>",
"17": "<p>Third curse: moving a neighbor&apos;s boundary marker (ʾăšer yasgîg gĕḇûl rēʿēhû). Land in Israel was covenant-allotted inheritance (naḥălâ), distributed by YHWH through the tribal allotment (Num 26; Josh 13–21). To move a boundary stone was to defraud both the neighbor and YHWH who distributed the land. Prov 22:28 and 23:10 repeat the prohibition. The Mesha Stele (Moabite king, ca. 840 BC) records land seizure from Israel, showing that boundary violations were a major ANE political and moral concern.</p>",
"18": "<p>Fourth curse: misleading a blind person on the road. Lev 19:14 parallels this: &quot;Do not curse the deaf or put a stumbling block in front of the blind.&quot; The blind person is a paradigmatic figure for all who are navigationally or informationally vulnerable — those who cannot verify what they are being told. The curse targets the exploitation of any form of disability or dependence. The principle extends across all situations where asymmetric knowledge creates power to deceive the vulnerable.</p>",
"19": "<p>Fifth curse: denying justice to the foreigner (gēr), the fatherless (yātôm), or the widow (ʾalmānâ). This is the triad of the most vulnerable in ANE society — those without a male protector, without property rights, without legal standing in the patronage system. YHWH describes himself as the defender of this triad (Deut 10:18; Ps 68:5). Judicial corruption targeting those with no family advocate is here elevated to a covenantal crime with divine sanction. The triad recurs throughout Deuteronomy: 10:18; 14:29; 16:11, 14; 24:17–21.</p>",
"20": "<p>Sixth curse: sleeping with his father&apos;s wife (stepmother). &quot;Violated his father&apos;s marriage&quot; — literally &quot;uncovered the corner/skirt of his father&quot; (gillâ kĕnap̄ ʾāḇîw), an idiom for accessing someone under the father&apos;s protective covering (marriage garment). Reuben&apos;s act in Gen 35:22 and Absalom&apos;s deliberate public act in 2 Sam 16:22 (as political statement of usurpation) illustrate that this offense carried both sexual and political-honor dimensions. The son who violates the father&apos;s marriage asserts dominance over the household.</p>",
"21": "<p>Seventh curse: bestiality (šōḵēḇ ʿim kol-bĕhēmâ, &quot;whoever lies with any animal&quot;). Also prohibited in Exod 22:19, Lev 18:23, and 20:15–16. The severity of covenant sanction signals the theological importance of the human-animal distinction in Israelite anthropology: humans bear the image of God (Gen 1:26–27) and must not blur the boundary between kinds. ANE neighbors (Hittite law codes) also prohibited this, indicating a shared cultural aversion with distinct theological grounding in Israel.</p>",
"22": "<p>Eighth curse: incest with sister — &quot;whether she is his father&apos;s daughter or his mother&apos;s daughter.&quot; The curse explicitly covers both full and half-sisters. This closure of the half-sister loophole is significant: the patriarchal narrative includes Abraham marrying Sarah, his half-sister (Gen 20:12). The Sinai covenant&apos;s prohibitions (Lev 18:9; 20:17) and now Deuteronomy&apos;s curses formally supersede the norms of the patriarchal period. Covenant law governs the community&apos;s present practice, not ancestral precedent.</p>",
"23": "<p>Ninth curse: sleeping with his mother-in-law (ḥōtantô). The relational violation destroys family integrity across two generations — the wife&apos;s generational line and the husband&apos;s marriage bond are both violated. The comprehensive reach of the sexual ethics section (vv.20–23) covers spousal, sibling, and in-law relationships, systematically protecting the family structure that sustains the covenant community.</p>",
"24": "<p>Tenth curse: secret attack on a neighbor (makkēh rēʿēhû bassāter, &quot;whoever strikes his neighbor in secret&quot;). Hidden violence against a neighbor, like the hidden idolatry of v.15, evades human courts. The public legal system could prosecute witnessed violence; covenantal curse fills the gap for attacks committed where no witness sees. The structural parallel between v.15 (secret idolatry) and v.24 (secret assault) shows the Dodecalogue&apos;s deliberate pattern: offenses against God and offenses against neighbor are subject to the same covenantal sanction.</p>",
"25": "<p>Eleventh curse: accepting a bribe to kill an innocent person (šōḥaḏ lĕhakkôt nepeš dām nāqî, &quot;bribe to strike/kill an innocent person&quot;). Judicial murder through bribed violence is among the most corrosive social sins in the prophetic literature (Prov 17:23; Isa 1:23; Jer 22:17; Mic 3:11; Ezek 22:12). It weaponizes the justice system against the innocent and destroys the social trust that covenant community requires. The specificity — bribed killing, not just bribery — targets the worst intersection of corruption and violence.</p>",
"26": "<p>Twelfth curse — the summary curse: &quot;Cursed is anyone who does not uphold the words of this law by carrying them out.&quot; The Dodecalogue ends not with a specific sin but with comprehensive covenant non-observance. This all-encompassing curse closes the section by placing the entire law under sanction: not just the eleven specific sins named above, but any failure to &quot;uphold&quot; (yāqîm, to establish, confirm, make stand) the law&apos;s full demands. Paul cites this verse in Gal 3:10 (&quot;Cursed is everyone who does not continue to do everything written in the Book of the Law&quot;) to establish that all who rely on the law are under its curse — the law&apos;s comprehensive reach is the basis for recognizing that only Christ, who bore the curse (Gal 3:13, citing Deut 21:23), can deliver those whom the law condemns.</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'deuteronomy')
    merge_comm(existing, DEUTERONOMY)
    save_comm('mkt-context', 'deuteronomy', existing)
    print('Deuteronomy 26-27 mkt-context written.')

if __name__ == '__main__':
    main()
